import React, { useState } from 'react';
import { useMusic } from '../context/MusicContext'; // Giả sử bạn dùng Context này
import axios from 'axios';
import { Play, Pause, SkipBack, SkipForward, Volume2, ListPlus } from 'lucide-react';

const GlobalPlayer = () => {
    const { currentSong, isPlaying, togglePlay } = useMusic();
    const [loading, setLoading] = useState(false);

    // Lấy thông tin user từ localStorage
    const user = JSON.parse(localStorage.getItem('user'));
    const userId = user?._id || user?.id;

    const handleCreatePlaylistWithCurrent = async () => {
        if (!userId) return alert("Vui lòng đăng nhập để tạo playlist!");
        if (!currentSong) return alert("Chưa có bài hát nào đang phát!");

        const playlistName = prompt(`Nhập tên Playlist mới cho bài "${currentSong.title}":`, "My Favorite Song");

        if (!playlistName) return; // Người dùng nhấn Hủy

        setLoading(true);
        try {
            const response = await axios.post('http://localhost:5000/api/songs/playlists', {
                title: playlistName,
                userId: userId,
                songIds: [currentSong._id] // Gửi kèm ID bài hát đang nghe
            });

            if (response.status === 201) {
                alert(`Đã tạo Playlist "${playlistName}" và thêm bài hát thành công!`);
            }
        } catch (error) {
            console.error("Lỗi tạo playlist:", error);
            alert("Không thể tạo playlist lúc này.");
        } finally {
            setLoading(false);
        }
    };

    if (!currentSong) return null; // Ẩn player nếu không có nhạc

    return (
        <div style={playerContainerStyle}>
            {/* Thông tin bài hát */}
            <div style={songInfoStyle}>
                <img src={`http://localhost:5000${currentSong.imageUrl}`} alt="thumb" style={thumbStyle} />
                <div>
                    <h4 style={{ margin: 0, fontSize: '14px' }}>{currentSong.title}</h4>
                    <p style={{ margin: 0, fontSize: '12px', color: '#b3b3b3' }}>{currentSong.artist}</p>
                </div>
            </div>

            {/* Bộ điều khiển nhạc */}
            <div style={controlsStyle}>
                <SkipBack size={20} />
                <button onClick={togglePlay} style={playBtnStyle}>
                    {isPlaying ? <Pause fill="black" /> : <Play fill="black" />}
                </button>
                <SkipForward size={20} />
            </div>

            {/* Các nút tính năng phụ */}
            <div style={extraControlsStyle}>
                {/* NÚT TẠO PLAYLIST MỚI THÊM VÀO ĐÂY */}
                <button 
                    onClick={handleCreatePlaylistWithCurrent} 
                    disabled={loading}
                    title="Tạo playlist từ bài này"
                    style={iconBtnStyle}
                >
                    <ListPlus size={22} color={loading ? "#888" : "#1db954"} />
                </button>
                
                <Volume2 size={20} />
            </div>
        </div>
    );
};

// CSS inline đơn giản
const playerContainerStyle = {
    position: 'fixed', bottom: 0, left: 0, right: 0, height: '80px',
    background: '#181818', color: 'white', display: 'flex',
    alignItems: 'center', justifyContent: 'space-between', padding: '0 20px',
    borderTop: '1px solid #282828', zIndex: 1000
};

const songInfoStyle = { display: 'flex', alignItems: 'center', gap: '15px', width: '30%' };
const thumbStyle = { width: '56px', height: '56px', borderRadius: '4px', objectFit: 'cover' };
const controlsStyle = { display: 'flex', alignItems: 'center', gap: '20px' };
const playBtnStyle = { background: 'white', border: 'none', borderRadius: '50%', padding: '8px', cursor: 'pointer' };
const extraControlsStyle = { display: 'flex', alignItems: 'center', gap: '15px', width: '30%', justifyContent: 'flex-end' };
const iconBtnStyle = { background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center' };

export default GlobalPlayer;
